// Validation defensive de l'input AVANT tout traitement (et avant tout appel LLM payant).
const body = $input.first().json.body || $input.first().json;

const transcript = (body.transcript || body.transcription || body.text || '').toString().trim();
const titre = (body.title || body.meeting_title || 'Meeting sans titre').toString().trim();
const dateMeeting = (body.date || new Date().toISOString().split('T')[0]).toString();
const participants = Array.isArray(body.participants) ? body.participants : [];

const erreurs = [];
if (!transcript) erreurs.push("Champ 'transcript' manquant ou vide");
if (transcript && transcript.length < 200) erreurs.push('Transcription trop courte (< 200 caracteres) — probablement un payload de test ou une erreur amont');
if (!/^\d{4}-\d{2}-\d{2}/.test(dateMeeting)) erreurs.push("Champ 'date' invalide (attendu : AAAA-MM-JJ)");

return [{
  json: {
    valide: erreurs.length === 0,
    raison: erreurs.join(' ; '),
    transcript,
    titre,
    dateMeeting,
    participants
  }
}];

// HTTP direct vers l'API LLM (pas de node LangChain : les longs prompts peuvent y etre tronques silencieusement).
const { transcript, titre, dateMeeting, participants } = $input.first().json;

const prompt = `Tu es l'analyste intelligence d'une equipe marketing. Analyse la transcription de reunion ci-dessous et retourne UNIQUEMENT un objet JSON valide, sans texte autour, avec cette structure exacte :
{
  "classification": "interne" | "client" | "prospect" | "veille",
  "entite": "nom de l'entreprise ou de l'equipe concernee (ou 'interne')",
  "resume": "resume factuel en 5-8 lignes",
  "points_cles": ["..."],
  "decisions": ["..."],
  "actions": [{ "quoi": "...", "qui": "...", "echeance": "AAAA-MM-JJ ou vide" }],
  "signaux": ["signal business ou marketing detecte (opportunite, risque, besoin exprime, objection...)"],
  "sujets_contenu": ["idee de contenu marketing exploitable issue de la reunion"]
}

Regles :
- Reste strictement factuel, n'invente RIEN qui ne soit pas dans la transcription.
- Si une categorie est vide, retourne un tableau vide.
- Redige en francais.

Titre de la reunion : ${titre}
Date : ${dateMeeting}
Participants declares : ${participants.join(', ') || 'non fournis'}

TRANSCRIPTION :
${transcript}`;

return [{ json: { prompt, titre, dateMeeting } }];

// Programmation defensive : ne jamais faire confiance au typage des outputs IA.
const toArray = (v) => Array.isArray(v) ? v : (typeof v === 'string' && v ? [v] : []);

const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
if (!text) throw new Error('Reponse LLM vide — verifier le credential et le modele');

let analyse;
try {
  analyse = JSON.parse(text);
} catch (e) {
  throw new Error('Reponse LLM non parsable en JSON : ' + text.slice(0, 300));
}

const classificationsValides = ['interne', 'client', 'prospect', 'veille'];
const classification = classificationsValides.includes(analyse.classification) ? analyse.classification : 'interne';

return [{
  json: {
    classification,
    entite: (analyse.entite || 'interne').toString(),
    resume: (analyse.resume || '').toString(),
    pointsCles: toArray(analyse.points_cles),
    decisions: toArray(analyse.decisions),
    actions: Array.isArray(analyse.actions) ? analyse.actions : [],
    signaux: toArray(analyse.signaux),
    sujetsContenu: toArray(analyse.sujets_contenu),
    titre: $('Construire prompt analyse').first().json.titre,
    dateMeeting: $('Construire prompt analyse').first().json.dateMeeting
  }
}];

const d = $input.first().json;

const slugify = (s) => s.toLowerCase()
  .normalize('NFD').replace(/[̀-ͯ]/g, '')
  .replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '')
  .slice(0, 60) || 'meeting';

const nomFichier = `${d.dateMeeting}--meeting--${slugify(d.entite)}--${slugify(d.titre)}.md`;

const liste = (arr) => arr.length ? arr.map(x => `- ${x}`).join('
') : '_Aucun_';
const actions = d.actions.length
  ? d.actions.map(a => `- [ ] ${a.quoi || a}${a.qui ? ' — **' + a.qui + '**' : ''}${a.echeance ? ' (échéance : ' + a.echeance + ')' : ''}`).join('
')
  : '_Aucune_';

const contenu = `---
type: meeting
source: transcription-automatique
date: ${d.dateMeeting}
classification: ${d.classification}
entite: "${d.entite}"
titre: "${d.titre.replace(/"/g, "'")}"
statut: a-trier
---

# ${d.titre}

## Résumé

${d.resume}

## Points clés

${liste(d.pointsCles)}

## Décisions

${liste(d.decisions)}

## Actions

${actions}

## Signaux détectés

${liste(d.signaux)}

## Idées de contenu

${liste(d.sujetsContenu)}
`;

return [{ json: { contenu, nomFichier, classification: d.classification, entite: d.entite, titre: d.titre } }];
